761	function calibrateMain(argv) {
762	  const fs = require('fs');
763	  const args = argv.slice(2);
764	  const jsonIdx = args.indexOf('--json');
765	  const jsonPath = jsonIdx !== -1 ? args[jsonIdx + 1] : null;
766	  const findings = runCalibration();
767	  if (jsonPath) fs.writeFileSync(jsonPath, JSON.stringify(findings, null, 2));
768	  process.stdout.write(JSON.stringify({ checker: 'identity', findings }) + '\n');
769	  return 0;
770	}
771	
772	if (require.main === module) {
773	  if (process.argv.includes('--calibrate')) {
774	    process.exit(calibrateMain(process.argv));
775	  } else {
776	    console.error('facts/identity.js is a library. Only --calibrate is runnable from the CLI.');
777	    process.exit(2);
778	  }
779	}
