21	        let b = ''; res.on('data', (d) => { b += d; if (b.length > 2_000_000) { try { req.destroy(); } catch (_e) {} } });
22	        res.on('end', () => { let j = null; try { j = JSON.parse(b); } catch (_e) {} resolve({ status: res.statusCode, json: j }); });
23	      });
24	      req.on('error', () => resolve(null)); req.on('timeout', () => { try { req.destroy(); } catch (_e) {} resolve(null); });
25	    } catch (_e) { resolve(null); }
26	  });
