2	/**
3	 * The one CLI runner for blocking gates (one-door, swallow-gate). Both gates share the same contract:
4	 *
5	 *   0. SELF-TEST first: prove, in memory, that the gate can see the class it exists to catch. A gate that
6	 *      fails its self-test exits 2 and every zero it ever printed is suspect.
7	 *   1. normal mode: scan the declared directories; violations exit 1, clean exits 0.
8	 *   2. --calibrate: scan eval/calibration-known-bad/fixtures/ instead and REQUIRE that the seeded
9	 *      violations are found. Missing dir or zero findings = exit 1. A zero you did not earn is a lie.
10	 *   3. --json <path>: additionally write findings JSON for the sweep normaliser.
11	 */
12	const fs = require('fs');
13	const path = require('path');
14	
15	const ROOT = path.resolve(__dirname, '..', '..');
16	const CALIBRATE_DIR = path.join('eval', 'calibration-known-bad', 'fixtures');
17	
18	// Shared flag parsing for every gate: --calibrate, --json <path>. writeJson is a no-op without --json.
19	function parseGateArgs(argv) {
20	  const args = argv.slice(2);
21	  const jsonIdx = args.indexOf('--json');
22	  const jsonPath = jsonIdx >= 0 ? args[jsonIdx + 1] : null;
23	  return {
24	    calibrate: args.includes('--calibrate'),
25	    jsonPath,
26	    writeJson: (findings) => {
27	      if (!jsonPath) return;
28	      fs.mkdirSync(path.dirname(jsonPath), { recursive: true });
29	      fs.writeFileSync(jsonPath, JSON.stringify(findings, null, 2));
30	    },
31	  };
32	}
33	
34	/**
35	 * opts = {
36	 *   name           gate name for messages, e.g. 'one-door'
37	 *   selfTest       () -> {pass, detail}
38	 *   scan           (dirs) -> {violations: [...], ...counters}
39	 *   toFindings     (violations) -> normaliser-shaped findings
40	 *   scanDirs       directories for the normal scan
41	 *   summary        (result) -> one summary line for the normal scan
42	 *   calibrateSummary (result) -> one summary line for the calibrate scan
43	 *   violationLine  (v) -> one line per violation
44	 * }
45	 */
46	function runGateCli(opts) {
47	  const { calibrate, writeJson } = parseGateArgs(process.argv);
48	
49	  const st = opts.selfTest();
50	  if (!st.pass) {
51	    console.error(opts.name + ' SELF-TEST FAILED: ' + st.detail);
52	    console.error('The gate cannot see the class it exists to catch. Every zero it reports is unearned.');
53	    process.exit(2);
54	  }
55	
56	  if (calibrate) {
57	    if (!fs.existsSync(path.join(ROOT, CALIBRATE_DIR))) {
58	      console.error(opts.name + ' CALIBRATION FAILED: ' + CALIBRATE_DIR + ' does not exist. There is nothing to earn a zero against.');
59	      process.exit(1);
60	    }
61	    const res = opts.scan([CALIBRATE_DIR]);
62	    writeJson(opts.toFindings(res.violations));
63	    console.log('  ' + opts.name + ' calibration: ' + opts.calibrateSummary(res));
64	    for (const v of res.violations) console.log('    CAUGHT ' + opts.violationLine(v));
65	    if (res.violations.length === 0) {
66	      console.error(opts.name + ' CALIBRATION FAILED: fixtures exist but zero violations found. The seeded bad input escaped.');
67	      process.exit(1);
68	    }
69	    process.exit(0);
70	  }
71	
72	  const res = opts.scan(opts.scanDirs);
73	  writeJson(opts.toFindings(res.violations));
74	  console.log('  ' + opts.name + ': ' + opts.summary(res) + ' (self-test: earned)');
75	  for (const v of res.violations) console.error('  ' + opts.violationLine(v));
76	  process.exit(res.violations.length > 0 ? 1 : 0);
