172	  try {
173	    safePath.assertSafeScanPath(p, { label: 'facts-abstain scan path' });
174	    abs = path.resolve(ROOT, p);
175	  } catch (e) {
176	    recordScanError(violations, String(p), e.message);
177	    return null;
178	  }
179	  if (!fs.existsSync(abs)) {
