203	// skip); a DIRECTLY named file carries no such excuse and fails closed (CR-41), recorded not swallowed.
204	function scanBundlesInFile(file, isDir, acc) {
205	  const rel = path.relative(ROOT, file).replace(/\\/g, '/');
206	  let parsed;
207	  try {
208	    parsed = JSON.parse(fs.readFileSync(file, 'utf8'));
209	  } catch (e) {
