262	function selfTestUnreachableBundle() {
263	  return {
264	    domain: 'selftest-unreachable.example',
265	    unreachable: true,
266	    corpus: { pages: [{ url: 'https://selftest-unreachable.example/', title: 'Attention Required!', text: 'Checking your browser before accessing.', jsonLd: [] }], footerText: '' },
267	    registers: {},
268	  };
269	}
270	
271	// selfTestResolverStubs() -> the three DELIBERATELY FAULTY/correct stub resolver triples CR-42
272	// requires (see the file-level comment above selfTest): never REAL_RESOLVERS.
273	function selfTestResolverStubs() {
274	  return {
275	    faultyNonAbstain: {
276	      resolveIdentity: () => ({ display_name: { value: 'Faulty Stub Co', confidence: 'weak' } }),
277	      resolveJurisdiction: () => ({ abstained: false, bound: [{ jurisdiction: 'UK' }] }),
278	      resolveSector: () => ({ value: 'law-firms', confidence: 'weak' }),
279	    },
280	    faultyThrowing: {
281	      resolveIdentity: () => { throw new Error('synthetic injected failure'); },
282	      resolveJurisdiction: () => { throw new Error('synthetic injected failure'); },
283	      resolveSector: () => { throw new Error('synthetic injected failure'); },
284	    },
285	    correctlyAbstaining: {
286	      resolveIdentity: () => ({ display_name: { value: null, confidence: 'abstain' } }),
287	      resolveJurisdiction: () => ({ abstained: true, bound: [] }),
288	      resolveSector: () => ({ value: null, confidence: 'abstain' }),
289	    },
