350	}
351	
352	function main() {
353	  const argv = process.argv.slice(2);
354	  const positional = argv.filter((a, i) => a !== '--calibrate' && a !== '--json' && argv[i - 1] !== '--json');
355	  runGateCli({
356	    name: 'facts-abstain',
357	    selfTest,
358	    scan,
359	    toFindings,
