2	// Phase 2.2 register grounding — turns "the site mentions UK" into "an official register confirms the firm is
3	// ESTABLISHED here". ADDITIVE + FAIL-OPEN: it can only ever ADD establishment evidence (never remove), so a real
4	// firm is never dropped if a register is unreachable. Free public registers (researched 2026-07):
5	//   CQC  — https://api.cqc.org.uk/public/v1  — NO KEY (Open Government Licence); add ?partnerCode=<id>. Healthcare.
6	//   Companies House — https://api.company-information.service.gov.uk — FREE self-service key (HTTP Basic, key as user).
7	//   FCA Financial Services Register — https://register.fca.org.uk/services/V0.1 — FREE key (email+key headers). Finance.
8	//   SRA Data Sharing API — SRA-registered organisations (law firms), JSON. Solicitors.
9	// Keys (when present) come from env; absent keys => that register is simply skipped (fail-open). No network in tests.
10	const https = require('https');
11	
12	const REGISTERS = {
13	  CQC:  { fam: 'UK', sector: ['healthcare'], keyEnv: null,                base: 'https://api.cqc.org.uk/public/v1' },     // no key
14	  CH:   { fam: 'UK', sector: null,           keyEnv: 'COMPANIES_HOUSE_KEY', base: 'https://api.company-information.service.gov.uk' },
15	  FCA:  { fam: 'UK', sector: ['finance','fintech','insurance'], keyEnv: 'FCA_API_KEY', base: 'https://register.fca.org.uk/services/V0.1' },
16	  SRA:  { fam: 'UK', sector: ['law-firms'],  keyEnv: 'SRA_API_KEY',     base: 'https://data.sra.org.uk' },
17	};
18	
19	function _get(url, headers, timeoutMs) {
20	  return new Promise(resolve => {
21	    try {
22	      const req = https.get(url, { headers: headers || {}, timeout: timeoutMs || 4000 }, res => {
23	        let b = ''; res.on('data', d => b += d); res.on('end', () => { try { resolve({ status: res.statusCode, json: JSON.parse(b) }); } catch (_) { resolve({ status: res.statusCode, json: null }); } });
24	      });
25	      req.on('error', () => resolve(null)); req.on('timeout', () => { req.destroy(); resolve(null); });
26	    } catch (_) { resolve(null); }
27	  });
28	}
29	
30	// Which registers are usable right now (no key needed, OR key present in env). Pure — safe to call in tests.
31	function availableRegisters(env = process.env) {
32	  const out = [];
33	  for (const [name, r] of Object.entries(REGISTERS)) { if (!r.keyEnv || env[r.keyEnv]) out.push(name); }
34	  return out; // CQC always present (no key)
35	}
36	
37	// Ground establishment for a firm. Returns { UK: { established_in:true, source:'CQC', ref } } or {} (fail-open).
38	// `probe` is injectable for tests (defaults to the live https GET). Never throws.
39	async function groundEstablishment({ name, companyNumber, sector, env = process.env, probe = null } = {}) {
40	  const get = probe || _get; const found = {};
41	  for (const rn of availableRegisters(env)) {
42	    const r = REGISTERS[rn];
43	    if (r.sector && sector && !r.sector.includes(String(sector).toLowerCase())) continue;
44	    try {
45	      let url = null, headers = {};
46	      if (rn === 'CH' && companyNumber) { url = `${r.base}/company/${encodeURIComponent(companyNumber)}`; headers = { Authorization: 'Basic ' + Buffer.from((env.COMPANIES_HOUSE_KEY || '') + ':').toString('base64') }; }
47	      else if (rn === 'CQC' && name) { url = `${r.base}/providers?partnerCode=tamazia&name=${encodeURIComponent(name)}`; }
48	      else if (rn === 'FCA' && name && env.FCA_API_KEY) { url = `${r.base}/Search?q=${encodeURIComponent(name)}&type=firm`; headers = { 'X-Auth-Email': env.FCA_EMAIL || '', 'X-Auth-Key': env.FCA_API_KEY }; }
49	      else if (rn === 'SRA' && name) { url = `${r.base}/organisations?name=${encodeURIComponent(name)}`; }
50	      if (!url) continue;
51	      const res = await get(url, headers, 4000);
52	      if (res && res.status === 200 && res.json && (Array.isArray(res.json) ? res.json.length : Object.keys(res.json).length)) {
53	        found[r.fam] = { established_in: true, source: rn, ref: (res.json.company_number || (res.json[0] && (res.json[0].locationId || res.json[0].id)) || true) };
54	      }
55	    } catch (_) { /* fail-open */ }
56	  }
57	  return found; // empty => no grounding; caller keeps corpus-based nexus unchanged
58	}
59	
60	// Merge register grounding INTO a corpus nexus map — additive only (never clears an established_in the corpus set).
61	function mergeGrounding(nexusMap, grounding) {
62	  const out = Object.assign({}, nexusMap || {});
63	  for (const fam of Object.keys(grounding || {})) {
64	    out[fam] = Object.assign({}, out[fam] || {}, { established_in: !!(grounding[fam].established_in) || !!(out[fam] && out[fam].established_in), established_source: grounding[fam].source });
65	  }
66	  return out;
67	}
68	module.exports = { REGISTERS, availableRegisters, groundEstablishment, mergeGrounding };
