44	// ── fallback engine: comment/string-aware scan for catch blocks ─────────────────────────────────────────────
45	
46	// Walk the source character by character, tracking string/template/comment context, and return the index just
47	// past the matching close brace for the brace at `openIdx`.
48	function matchBrace(src, openIdx) {
49	  let depth = 0;
50	  let i = openIdx;
51	  while (i < src.length) {
52	    const c = src[i];
53	    const next = src[i + 1];
54	    if (c === '/' && next === '/') { const nl = src.indexOf('\n', i); i = nl === -1 ? src.length : nl + 1; continue; }
55	    if (c === '/' && next === '*') { const end = src.indexOf('*/', i + 2); i = end === -1 ? src.length : end + 2; continue; }
56	    if (c === '\'' || c === '"' || c === '`') {
57	      const q = c;
58	      i++;
59	      while (i < src.length && src[i] !== q) { if (src[i] === '\\') i++; i++; }
60	      i++;
61	      continue;
62	    }
63	    if (c === '{') depth++;
64	    if (c === '}') { depth--; if (depth === 0) return i + 1; }
65	    i++;
66	  }
67	  return src.length;
68	}
