126	function judgeCatch(src, c) {
127	  const body = src.slice(c.bodyStart, c.bodyEnd);
128	  // Justification may sit inside the body or on the two lines immediately above the catch.
129	  const before = src.slice(Math.max(0, src.lastIndexOf('\n', Math.max(0, src.lastIndexOf('\n', c.start - 1) - 1))), c.start);
