1	#!/usr/bin/env node
2	'use strict';
3	/**
4	 * FACT-LINEAGE: single producer asserted in CI; the renderer introduces no facts.
5	 *
6	 * Reads payload/schema/facts-lineage.json, the declared lineage of every fact that reaches a client:
7	 *
8	 *   {
9	 *     "facts": {
10	 *       "<fact-id>": {
11	 *         "producer": "facts/jurisdiction.js",        one module, one door
12	 *         "consumers": ["payload/composer/...", ...]  optional, informational
13	 *       }
14	 *     }
15	 *   }
16	 *
17	 * Checks, when the manifest exists:
18	 *   1. every fact declares exactly ONE producer (a string, not a list)
19	 *   2. the producer file exists in the repo (a lineage pointing at a ghost is a lie)
20	 *   3. no two facts share an id (JSON.parse already guarantees this; kept for the array form)
21	 *   4. cross-check against tools/one-door/facts.json: every fact declared there must appear here with the
22	 *      same door, once the manifest exists
23	 *
24	 * The manifest does not exist yet in P0. Absence is a WARNING and exit 0: this checker must run green on
25	 * the near-empty repo today, and the payload schema owner will land the manifest in P4. The moment the file
26	 * exists, every check above becomes blocking.
27	 *
28	 * Modes:
29	 *   node tools/fact-lineage/check.js                  check, exit 1 on violations (exit 0 + WARNING if absent)
30	 *   node tools/fact-lineage/check.js --json <path>    also write findings JSON for the sweep normaliser
31	 */
32	const fs = require('fs');
33	const path = require('path');
34	
35	const { parseGateArgs, ROOT } = require('../lib/gate-cli');
36	
37	const MANIFEST = path.join(ROOT, 'payload', 'schema', 'facts-lineage.json');
38	const ONE_DOOR_FACTS = path.join(ROOT, 'tools', 'one-door', 'facts.json');
39	
40	function loadManifest(p) {
41	  const doc = JSON.parse(fs.readFileSync(p, 'utf8'));
42	  // Accept both the object form {facts: {id: {...}}} and an array form [{id, producer, ...}].
43	  if (Array.isArray(doc.facts)) {
44	    const map = {};
45	    for (const f of doc.facts) {
46	      if (map[f.id]) throw new Error('duplicate fact id in lineage manifest: ' + f.id);
47	      map[f.id] = f;
48	    }
49	    return map;
50	  }
51	  if (doc.facts && typeof doc.facts === 'object') return doc.facts;
52	  throw new Error('facts-lineage.json has no facts key (object or array expected)');
53	}
54	
55	function check(manifestPath) {
56	  const violations = [];
57	  const facts = loadManifest(manifestPath);
58	  const ids = Object.keys(facts);
59	  if (ids.length === 0) violations.push({ fact: '(none)', message: 'lineage manifest exists but declares zero facts: an empty manifest is a confident zero' });
60	
61	  for (const id of ids) {
62	    const f = facts[id];
63	    const producer = f.producer;
64	    if (typeof producer !== 'string' || producer.length === 0) {
65	      violations.push({ fact: id, message: 'fact must declare exactly ONE producer as a string; got ' + JSON.stringify(producer) });
66	      continue;
67	    }
68	    if (Array.isArray(f.producers) || /,/.test(producer)) {
69	      violations.push({ fact: id, message: 'more than one producer declared: that is two doors by construction' });
70	    }
71	    const abs = path.join(ROOT, producer);
72	    if (!fs.existsSync(abs)) {
73	      violations.push({ fact: id, message: 'declared producer does not exist: ' + producer + ' (a lineage pointing at a ghost is a lie)' });
74	    }
75	  }
76	
77	  // Cross-check against the one-door manifest: the two declarations must agree.
78	  if (fs.existsSync(ONE_DOOR_FACTS)) {
79	    const od = JSON.parse(fs.readFileSync(ONE_DOOR_FACTS, 'utf8'));
80	    for (const f of od.facts || []) {
81	      const here = facts[f.id];
82	      if (!here) {
83	        violations.push({ fact: f.id, message: 'declared in tools/one-door/facts.json but missing from the lineage manifest' });
84	        continue;
85	      }
86	      const allowed = f.allowed_producers || [];
87	      const ok = allowed.some((a) => (a.endsWith('/') ? String(here.producer).startsWith(a) : here.producer === a));
88	      if (!ok) violations.push({ fact: f.id, message: 'lineage producer ' + here.producer + ' disagrees with one-door allowed door ' + allowed.join(', ') });
89	    }
90	  }
91	  return { violations, declared: ids.length };
92	}
93	
94	function toFindings(violations) {
95	  return violations.map((v) => ({
96	    tool: 'fact-lineage',
97	    ruleId: 'lineage:' + v.fact,
98	    file: 'payload/schema/facts-lineage.json',
99	    startLine: 0,
100	    endLine: 0,
101	    level: 'error',
102	    message: '[' + v.fact + '] ' + v.message,
103	    snippet: v.fact,
104	  }));
105	}
106	
107	function main() {
108	  const { writeJson } = parseGateArgs(process.argv);
109	
110	  if (!fs.existsSync(MANIFEST)) {
111	    console.log('  fact-lineage: WARNING: payload/schema/facts-lineage.json does not exist yet (expected in P0; the payload schema owner lands it in P4). 0 facts checked. This becomes blocking the moment the file exists.');
112	    writeJson([]);
113	    process.exit(0);
114	  }
115	
116	  const { violations, declared } = check(MANIFEST);
117	  writeJson(toFindings(violations));
118	  console.log('  fact-lineage: ' + declared + ' facts declared, ' + violations.length + ' violations');
119	  for (const v of violations) console.error('  LINEAGE [' + v.fact + '] ' + v.message);
120	  process.exit(violations.length > 0 ? 1 : 0);
121	}
122	
123	if (require.main === module) main();
124	module.exports = { check, loadManifest, toFindings };
