// in a hard Promise.race deadline; a slow dependency degrades the mint, it never hangs it).
//
// withDeadline NEVER rejects and never throws synchronously for a caller: it always resolves to a
// discriminated result, so a caller can treat "timed out", "threw" and "resolved" uniformly without
// its own try/catch. The caller (evidence/registers/lib/lookup-runner.js) is the one place that
// turns each of these outcomes into a row-absent + loud note (C-041 doctrine).

const DEFAULT_DEADLINE_MS = 6000;

// withDeadline(fn, ms, label) -> Promise<{ok:true, value} | {ok:false, reason:'timeout'|'error', error?, label}>
// `fn` is a zero-argument thunk returning a Promise (or a plain value); it is invoked exactly once.
function withDeadline(fn, ms, label) {
  const budget = Number.isFinite(ms) && ms > 0 ? ms : DEFAULT_DEADLINE_MS;
  return new Promise((resolve) => {
    let settled = false;
    const timer = setTimeout(() => {
      if (settled) return;
      settled = true;
      resolve({ ok: false, reason: 'timeout', label: label || null, ms: budget });
    }, budget);
    if (timer && typeof timer.unref === 'function') timer.unref();

    let started;
    try {
      started = fn();
    } catch (err) {
      if (!settled) {
        settled = true;
        clearTimeout(timer);
        resolve({ ok: false, reason: 'error', error: err, label: label || null });
      }
      return;
    }
    Promise.resolve(started).then(
      (value) => {
        if (settled) return;
        settled = true;
        clearTimeout(timer);
        resolve({ ok: true, value });
      },
      (err) => {
        if (settled) return;
        settled = true;
        clearTimeout(timer);
        resolve({ ok: false, reason: 'error', error: err, label: label || null });
      }
    );
  });
}

module.exports = { withDeadline, DEFAULT_DEADLINE_MS };

'use strict';
// evidence/registers/lib/name-match.js — the ONE name-match algorithm every register module in this
// directory shares (Constitution C-004): a register row may be returned ONLY on a genuine name match
// against the query, never merely because an API answered HTTP 200 with a non-empty body. Ported and
// strengthened from the old estate's register-check.js / register-grounding.js, which accepted ANY
// non-empty response as establishment evidence, and ico-register.js's SQL prefix match, which had no
// scoring and no rejection of a merely-similar name.
//
// ALGORITHM: normalise both names (lowercase, "&" -> "and", strip legal-entity suffixes via the one
// vocabulary door facts/vocabulary.js, collapse whitespace), tokenise on non-alphanumeric boundaries
// dropping short/connective tokens, then score by Jaccard similarity (shared tokens divided by the
// union of tokens). A match requires the score to clear MATCH_THRESHOLD AND at least one shared
// token. This is deliberately NOT a substring or prefix test (a substring/prefix match on a
// host/name is the C-059 class this codebase bans lint-wide) and deliberately not "any shared word",
// which is exactly what let a register hit attach to an unrelated company in the old estate sharing
// only a generic first word.
//
// THRESHOLD JUSTIFICATION (MATCH_THRESHOLD = 0.6):
//  - An exact or suffix-only-differing name (the overwhelming common case: the query and the register
//    row differ only by a legal suffix such as LLP/Ltd) normalises to identical token sets, so the
//    score is 1.0.
//  - A register variant carrying one extra token the query lacks (a common real shape: the query is a
//    shortened trading name and the register row spells out a fuller form) still clears the threshold
//    with margin: two shared tokens out of a three-token union scores 0.667.
//  - A two-word query sharing only its FIRST word with an unrelated two-word candidate — the
//    "Kingsley Napley LLP" vs "Kingsley Carpets Ltd" class this module exists to reject — scores
//    0.333 (one shared token out of a three-token union), comfortably below the threshold.
//  - 0.6 sits in the gap between these two real shapes with margin on both sides; it is not tuned to
//    a single fixture value. See name-match.test.js and the eval/calibration-known-bad/fixtures/
//    p3-register-*.json fixtures for both directions (true positive still fires, near-miss stays
//    rejected).
//
// A single shared token is required even when the ratio alone would pass, as defence in depth for
// very short names; a one-token query matching a one-token candidate exactly already scores 1.0 and
// satisfies both conditions, so this changes nothing for the common short-name case.

let LEGAL_ENTITY_SUFFIXES;
try {
  ({ LEGAL_ENTITY_SUFFIXES } = require('../../facts/vocabulary.js'));
} catch (err) {
  // facts/vocabulary.js is the one door for this word list (Constitution Rule 1); if it is ever
  // absent this module must fail closed and loudly rather than silently matching against an empty
  // suffix list, which would make every legal-suffix token count toward the name score and inflate
  // every match.
  throw new Error(
    'evidence/registers/lib/name-match.js: facts/vocabulary.js is required for LEGAL_ENTITY_SUFFIXES '
    + 'and could not be loaded: ' + err.message
  );
}

const MIN_TOKEN_CHARS = 3;
const MIN_QUERY_LEN = 4; // a normalised query shorter than this is too ambiguous to search safely
const MATCH_THRESHOLD = 0.6;

const CONNECTIVE_WORDS = new Set(['and', 'the', 'of', 'for']);

const SUFFIX_BODY = '\\b(?:'
  + LEGAL_ENTITY_SUFFIXES.map((s) => String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|')
  + ')\\b\\.?';
const SUFFIX_RX = new RegExp(SUFFIX_BODY, 'gi');

function tidy(s) {
  return String(s == null ? '' : s).replace(/\s+/g, ' ').trim();
}

function stripLegalSuffixes(s) {
  return tidy(String(s || '').replace(SUFFIX_RX, ' '));
}

function normaliseName(name) {
  const lowered = String(name || '').toLowerCase().replace(/&/g, ' and ');
  return stripLegalSuffixes(lowered);
}

function tokensOf(name) {
  return normaliseName(name)
    .split(/[^a-z0-9]+/)
    .filter((t) => t.length >= MIN_TOKEN_CHARS && !CONNECTIVE_WORDS.has(t));
}

// queryTooShort(name) -> true when the normalised query carries too little signal to search a
// register safely (mirrors the port source's MIN_CONFIDENT_LEN doctrine: a name stem shorter than
// this matches too many candidates to be evidence).
function queryTooShort(name) {
  return normaliseName(name).replace(/[^a-z0-9]/g, '').length < MIN_QUERY_LEN;
}

// scoreMatch(queryName, candidateName) -> {score, sharedTokens, queryTokens, candidateTokens}. Pure;
// never throws. An empty token set on either side scores 0 (nothing safe to compare).
function scoreMatch(queryName, candidateName) {
  const q = new Set(tokensOf(queryName));
  const c = new Set(tokensOf(candidateName));
  if (q.size === 0 || c.size === 0) {
    return { score: 0, sharedTokens: [], queryTokens: [...q], candidateTokens: [...c] };
  }
  const shared = [...q].filter((t) => c.has(t));
  const union = new Set([...q, ...c]);
  return { score: shared.length / union.size, sharedTokens: shared, queryTokens: [...q], candidateTokens: [...c] };
}

function isNameMatch(queryName, candidateName) {
  const { score, sharedTokens } = scoreMatch(queryName, candidateName);
  return score >= MATCH_THRESHOLD && sharedTokens.length >= 1;
}

// bestCandidate(queryName, candidates, nameOf) -> {candidate, score, matched, nameQueried, nameMatched}
// or null when the candidate list is empty / carries no usable name. Picks the single highest-scoring
// candidate; `matched` tells the caller whether it clears MATCH_THRESHOLD. Callers decide what "no
// acceptable candidate" means for their own row-absence note (C-004: never fabricate a partial row).
function bestCandidate(queryName, candidates, nameOf) {
  let best = null;
  for (const cand of candidates || []) {
    const candName = nameOf(cand);
    if (!candName) continue;
    const { score } = scoreMatch(queryName, candName);
    if (!best || score > best.score) best = { candidate: cand, score, name: candName };
  }
  if (!best) return null;
  return {
    candidate: best.candidate,
    score: best.score,
    matched: best.score >= MATCH_THRESHOLD,
    nameQueried: tidy(queryName),
    nameMatched: best.name,
  };
}

// A minimal, LOCAL, non-authoritative fallback query seed derived from a domain — NOT the identity
// fact (facts/identity.js is the one door for display_name/legal_name, Constitution Rule 1). Used
// only to give a register search something to query when no company-name hint exists yet: P3
// evidence collection runs BEFORE identity resolution, not after, so identity's own resolver cannot
// be consulted here without an unwanted evidence-to-facts dependency cycle.
function domainStemFallback(domain) {
  let d = String(domain || '').toLowerCase().trim()
    .replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0].split(':')[0];
  if (!d) return '';
  const parts = d.split('.').filter(Boolean);
  if (parts.length <= 1) return parts[0] || '';
  return parts[parts.length - 2];
}

module.exports = {
  MIN_TOKEN_CHARS,
  MIN_QUERY_LEN,
  MATCH_THRESHOLD,
  normaliseName,
  tokensOf,
  queryTooShort,
  scoreMatch,
  isNameMatch,
  bestCandidate,
  domainStemFallback,
};

'use strict';
// evidence/registers/lib/notes.js — the shared notes[] entry shape every register module in this
// directory uses when a field is absent (C-041 doctrine, ported from the browser evidence lane's own
// rule in docs/P3-ACCEPTANCE.md: a missing evidence-lane dependency is logged loudly and recorded,
// never silently skipped). `kind` is one of:
//   'skipped'  — a register was correctly judged not applicable (e.g. SRA on a hospitality site);
//                this is a budget decision (Rule 8), not a gap.
//   'degraded' — a register SHOULD have been checked but could not be: a missing key/config, a fetch
//                error, or a timeout. This is the founder-blocked / infra-gap class.
//   'no_match' — the register answered but no candidate cleared the name-match threshold (C-004), or
//                answered with zero candidates at all.

function makeNote(register, kind, reason, detail, log) {
  const note = { register, kind, reason, detail: detail || null };
  if (typeof log === 'function') {
    try {
      log({ level: 'warn', source: 'evidence/registers', ...note });
    } catch (_err) {
      // FAIL-OPEN: an injected logger throwing must never break the lookup itself. The note object
      // returned to the caller (and pushed onto bundle.notes[]) IS the durable record of this event;
      // the logger call above is a best-effort side channel on top of it, not the record itself.
    }
  }
  return note;
}

module.exports = { makeNote };

'use strict';
// evidence/registers/lib/lookup-runner.js — the ONE execution flow every register module in this
// directory shares: guard the query length, check for a required key/config, make the single
// deadline-wrapped fetch, and judge the response against the shared name-match gate (C-004). Each
// register module supplies only its own request shape, response parsing and row fields; this file
// owns the flow they all have in common so a fix or a strengthening (a new guard, a new note kind)
// lands once, not six times (the C-188 "stale door" doctrine applied to evidence collection, not just
// facts production).
const { withDeadline, DEFAULT_DEADLINE_MS } = require('./deadline');
const { queryTooShort, bestCandidate } = require('./name-match');
const { makeNote } = require('./notes');

// judgeOutcome(spec, outcome) -> {row, note}. `outcome` is a withDeadline() result: either
// {ok:false, reason:'timeout'|'error', ...} or {ok:true, value:{status, json}|null}. Never throws:
// every branch here is a typed, recorded degrade (never a fabricated or partial row).
function judgeOutcome(spec, outcome) {
  const { register, query, log } = spec;
  if (!outcome.ok) {
    const reason = outcome.reason === 'timeout' ? 'timeout' : 'fetch_error';
    const detail = outcome.reason === 'timeout'
      ? 'no response within the call deadline'
      : 'fetch failed: ' + (outcome.error && outcome.error.message);
    return { row: null, note: makeNote(register, 'degraded', reason, detail, log) };
  }
  const res = outcome.value;
  if (!res || res.status !== 200 || res.json == null) {
    const status = res && res.status;
    return { row: null, note: makeNote(register, 'degraded', 'unexpected_response', 'register answered with status ' + status, log) };
  }
  const candidates = spec.extractCandidates(res.json) || [];
  if (candidates.length === 0) {
    return { row: null, note: makeNote(register, 'no_match', 'no_candidates_returned', 'register returned zero candidates for "' + query + '"', log) };
  }
  const best = bestCandidate(query, candidates, (c) => c.name);
  if (!best || !best.matched) {
    const nearest = best ? (best.nameMatched + ' (score ' + best.score.toFixed(2) + ')') : '(none)';
    const detail = 'nearest candidate for "' + query + '" was ' + nearest
      + '; refused (C-004: a non-empty response is not a match without a real name match)';
    return { row: null, note: makeNote(register, 'no_match', 'below_threshold', detail, log) };
  }
  const row = spec.buildRow(best.candidate, best);
  row.source = register;
  row.fetched_at = new Date().toISOString();
  row.query = query;
  row.match = { name_queried: best.nameQueried, name_matched: best.nameMatched, score: Number(best.score.toFixed(4)) };
  return { row, note: null };
}

// runLookup(spec) -> Promise<{row, note}> for ONE register call. `spec` fields:
//   register          register id, e.g. 'companies_house'
//   query             the company-name candidate being searched
//   fetchFn           injected fetch(url, options) -> Promise<{status, json}|null> (Rule 9: the ONLY
//                     way this module ever touches the network; never called directly by a submodule)
//   deadlineMs        per-call budget (Rule 9); DEFAULT_DEADLINE_MS if not given
//   log               optional structured logger, forwarded to every note
//   requiredKeyNote   optional {present:false, reason, detail}; when present.present is false this
//                     lookup degrades on missing key/config WITHOUT ever calling fetchFn
//   buildRequest()    -> {url, headers, requestKey}
//   extractCandidates(json) -> [{name, raw}]
//   buildRow(candidate, best) -> the register-specific row object (source/fetched_at/query/match are
//                     added by judgeOutcome above, never by the submodule — C-005: only the
//                     establishing call stamps provenance, and it is stamped in exactly one place)
async function runLookup(spec) {
  const { register, query, fetchFn, deadlineMs, log } = spec;
  if (queryTooShort(query)) {
    const detail = 'normalised query "' + query + '" is too short to search a register safely';
    return { row: null, note: makeNote(register, 'no_match', 'query_too_short', detail, log) };
  }
  if (spec.requiredKeyNote && spec.requiredKeyNote.present === false) {
    return { row: null, note: makeNote(register, 'degraded', spec.requiredKeyNote.reason, spec.requiredKeyNote.detail, log) };
  }
  const { url, headers, requestKey } = spec.buildRequest();
  const outcome = await withDeadline(() => fetchFn(url, { headers, requestKey }), deadlineMs || DEFAULT_DEADLINE_MS, register);
  return judgeOutcome(spec, outcome);
}

module.exports = { runLookup, judgeOutcome };

'use strict';
// evidence/registers/companies-house.js — UK Companies House free-tier company search.
//
// Port source: cowork-os-fresh src/lib/audit/register-check.js `_companiesHouse()` (accepted ANY
// non-empty search response as a match, caution C-004 — false establishment nexus). Strengthened
// here: a candidate is returned only when evidence/registers/lib/name-match.js scores it at or above
// MATCH_THRESHOLD against the query (see that module's header for the threshold justification and
// the near-miss rejection case this guards against).
//
// This module produces NO client-facing fact of its own (Constitution Rule 1): it only supplies a
// pre-fetched, binary-matched evidence row that facts/identity.js's readCompaniesHouseRow may then
// read from bundle.registers.companiesHouse. facts/identity.js stays the one door for legal_name,
// company_number and registered_office.
//
// Free tier: a self-service Companies House API key is required (HTTP Basic auth, the key as the
// username, no password — register one at the Companies House developer hub). An absent key means
// this lookup degrades loudly: no guess, no fabricated row.
const { runLookup } = require('./lib/lookup-runner');

const SEARCH_BASE = 'https://api.company-information.service.gov.uk/search/companies';

function buildRequest(query, apiKey) {
  const url = SEARCH_BASE + '?q=' + encodeURIComponent(query.slice(0, 80)) + '&items_per_page=5';
  const headers = { Authorization: 'Basic ' + Buffer.from(apiKey + ':').toString('base64') };
  return { url, headers, requestKey: 'companies_house.search' };
}

// extractCandidates(json) -> [{name, raw}]. The search endpoint's items array carries a display
// title and a company number per candidate; a candidate with no number is not usable evidence.
function extractCandidates(json) {
  const items = Array.isArray(json && json.items) ? json.items : [];
  return items
    .filter((it) => it && it.company_number)
    .map((it) => ({ name: String(it.title || ''), raw: it }));
}

// buildRow(candidate) -> the companies_house-specific row fields (source/fetched_at/query/match are
// added by lib/lookup-runner.js, never here). The search endpoint carries no registered-office
// address; a follow-up profile fetch would be needed to populate one. Left absent rather than
// guessed — facts/identity.js already treats a missing office as abstain, never a default.
function buildRow(candidate) {
  return {
    company_name: candidate.name || null,
    company_number: candidate.raw.company_number,
    company_status: candidate.raw.company_status || null,
    registered_office_address: null,
  };
}

async function lookupCompaniesHouse({ query, fetchFn, deadlineMs, keys, log }) {
  const apiKey = keys && keys.companiesHouse;
  return runLookup({
    register: 'companies_house',
    query,
    fetchFn,
    deadlineMs,
    log,
    requiredKeyNote: apiKey ? null : {
      present: false,
      reason: 'missing_key',
      detail: 'no Companies House API key supplied on keys.companiesHouse; register a free self-service key at the Companies House developer hub',
    },
    buildRequest: () => buildRequest(query, apiKey),
    extractCandidates,
    buildRow,
  });
}

module.exports = { lookupCompaniesHouse, extractCandidates, buildRow };

'use strict';
// evidence/registers/gleif.js — the Global LEI Index (GLEIF), a free, keyless public register of
// Legal Entity Identifiers covering entities across most jurisdictions (not UK-specific, unlike the
// other five modules in this directory). No port source names GLEIF by name; it is added here as a
// genuine "free-tier API" strengthening this evidence lane beyond the UK-only register set the old
// register-check.js checked, matching facts/README.md's Tier-A register-match doctrine (a worldwide,
// name-matched LEI record is exactly the kind of Tier-A signal facts/jurisdiction.js can use).
const { runLookup } = require('./lib/lookup-runner');

const SEARCH_BASE = 'https://api.gleif.org/api/v1/lei-records';

function buildRequest(query) {
  const url = SEARCH_BASE
    + '?filter%5Bentity.legalName%5D=' + encodeURIComponent(query.slice(0, 80))
    + '&page%5Bsize%5D=5';
  return { url, headers: {}, requestKey: 'gleif.lei_records' };
}

function addressLine(addr) {
  if (!addr || typeof addr !== 'object') return null;
  const lines = Array.isArray(addr.addressLines) ? addr.addressLines : [];
  const parts = lines.concat([addr.city, addr.region, addr.postalCode, addr.country]).filter(Boolean);
  return parts.length ? parts.join(', ') : null;
}

// extractCandidates(json) -> [{name, raw}]. GLEIF's JSON:API response shape carries each candidate's
// display name at attributes.entity.legalName.name and its LEI at the record's own id field.
function extractCandidates(json) {
  const data = Array.isArray(json && json.data) ? json.data : [];
  return data
    .filter((d) => d && d.id && d.attributes && d.attributes.entity)
    .map((d) => ({ name: String((d.attributes.entity.legalName || {}).name || ''), raw: d }));
}

function buildRow(candidate) {
  const entity = candidate.raw.attributes.entity;
  return {
    entity_name: candidate.name || null,
    lei: candidate.raw.id,
    entity_status: entity.status || null,
    registered_office_address: addressLine(entity.legalAddress),
  };
}

async function lookupGleif({ query, fetchFn, deadlineMs, log }) {
  return runLookup({
    register: 'gleif',
    query,
    fetchFn,
    deadlineMs,
    log,
    requiredKeyNote: null, // public, keyless endpoint: always attempted
    buildRequest: () => buildRequest(query),
    extractCandidates,
    buildRow,
  });
}

module.exports = { lookupGleif, extractCandidates, buildRow };

'use strict';
// evidence/registers/sra.js — the SRA (Solicitors Regulation Authority) Data Sharing Platform,
// organisation search. Port source: cowork-os-fresh src/lib/compliance/register-grounding.js (the
// SRA entry: base https://data.sra.org.uk, path /organisations?name=... — a public organisation
// search that answers a bare JSON array, no subscription key required for this endpoint).
// Strengthened here with the shared name-match gate (C-004): the old register-grounding.js treated
// ANY non-empty array as establishment evidence with no scoring at all.
const { runLookup } = require('./lib/lookup-runner');
const { makeNote } = require('./lib/notes');

const SEARCH_BASE = 'https://data.sra.org.uk/organisations';

// Only a law-firms/barristers caller should pay for this lookup (Rule 8: budgets are caps, and an
// irrelevant register call is a wasted one). An unspecified sector still tries: the register itself
// can corroborate or contradict a sector guess (caution C-014), so withholding the call just because
// the sector is not yet known would defeat that purpose.
const APPLICABLE_SECTORS = new Set(['law-firms', 'barristers']);
function applies(sector) {
  return !sector || APPLICABLE_SECTORS.has(String(sector).toLowerCase());
}

function buildRequest(query, apiToken) {
  const headers = apiToken ? { Authorization: 'Bearer ' + apiToken } : {};
  const url = SEARCH_BASE + '?name=' + encodeURIComponent(query.slice(0, 80));
  return { url, headers, requestKey: 'sra.organisations' };
}

// extractCandidates(json) -> [{name, raw}]. The endpoint answers a bare array of organisation
// objects; each candidate's display name may arrive under either camelCase or snake_case field name
// depending on the API version fetched.
function extractCandidates(json) {
  const items = Array.isArray(json) ? json : [];
  return items
    .filter((it) => it && (it.organisationName || it.name))
    .map((it) => ({ name: String(it.organisationName || it.name || ''), raw: it }));
}

function addressLine(raw) {
  const parts = [raw.addressLine1, raw.town, raw.postcode].filter(Boolean);
  return parts.length ? parts.join(', ') : null;
}

function buildRow(candidate) {
  const raw = candidate.raw;
  return {
    organisation_name: candidate.name || null,
    sra_number: raw.sraNumber || raw.sra_number || null,
    firm_type: raw.firmType || raw.firm_type || null,
    registered_office_address: addressLine(raw),
  };
}

async function lookupSra({ query, sector, fetchFn, deadlineMs, keys, log }) {
  if (!applies(sector)) {
    const detail = 'sector "' + sector + '" is not law-firms/barristers; SRA lookup skipped (Rule 8 budget cap)';
    return { row: null, note: makeNote('sra', 'skipped', 'sector_not_applicable', detail, log) };
  }
  const apiToken = keys && keys.sra;
  return runLookup({
    register: 'sra',
    query,
    fetchFn,
    deadlineMs,
    log,
    requiredKeyNote: null, // the organisation search endpoint is publicly queryable without a key
    buildRequest: () => buildRequest(query, apiToken),
    extractCandidates,
    buildRow,
  });
}

module.exports = { lookupSra, applies, extractCandidates, buildRow };

'use strict';
// evidence/registers/cqc.js — the CQC (Care Quality Commission) provider register.
//
// Port source: cowork-os-fresh src/lib/audit/register-check.js `_cqc()` (accepted the first provider
// result as a match, no scoring at all — C-004) and register-grounding.js (documents the base
// https://api.cqc.org.uk/public/v1, Open Government Licence).
//
// FOUNDER-BLOCKED IN THIS ESTATE (2026-07): CLAUDE.md records CQC_PARTNER_CODE and CQC_API_KEY as
// blank, pending registration at the CQC developer portal. This module therefore degrades loudly on
// every real call in this estate today (see the missing_key note below) — this is expected, reported
// honestly, and is not a bug in this module.
const { runLookup } = require('./lib/lookup-runner');
const { makeNote } = require('./lib/notes');

const SEARCH_BASE = 'https://api.cqc.org.uk/public/v1/providers';

const APPLICABLE_SECTORS = new Set([
  'healthcare', 'dental', 'aesthetics', 'pharmacy', 'telemedicine', 'care-homes', 'fertility',
]);
function applies(sector) {
  return !sector || APPLICABLE_SECTORS.has(String(sector).toLowerCase());
}

function buildRequest(query, cqcKeys) {
  const url = SEARCH_BASE
    + '?partnerCode=' + encodeURIComponent(cqcKeys.partnerCode)
    + '&name=' + encodeURIComponent(query.slice(0, 80));
  return { url, headers: { 'Ocp-Apim-Subscription-Key': cqcKeys.apiKey }, requestKey: 'cqc.providers' };
}

// extractCandidates(json) -> [{name, raw}]. The provider search answers either {providers:[...]} or
// a bare array; each provider carries a display name and an id under one of two casings.
function extractCandidates(json) {
  const items = Array.isArray(json && json.providers) ? json.providers : (Array.isArray(json) ? json : []);
  return items
    .filter((it) => it && (it.providerId || it.providerID))
    .map((it) => ({ name: String(it.name || it.providerName || ''), raw: it }));
}

function addressLine(raw) {
  const parts = [raw.postalAddressLine1, raw.postalAddressTownCity, raw.postalAddressCounty, raw.postalPostCode]
    .filter(Boolean);
  return parts.length ? parts.join(', ') : null;
}

function buildRow(candidate) {
  const raw = candidate.raw;
  return {
    provider_name: candidate.name || null,
    provider_id: raw.providerId || raw.providerID,
    registered_office_address: addressLine(raw),
