// A minimal, LOCAL, non-authoritative fallback query seed derived from a domain — NOT the identity
// fact (facts/identity.js is the one door for display_name/legal_name, Constitution Rule 1). Used
// only to give a register search something to query when no company-name hint exists yet: P3
// evidence collection runs BEFORE identity resolution, not after, so identity's own resolver cannot
// be consulted here without an unwanted evidence-to-facts dependency cycle.
function domainStemFallback(domain) {
  let d = String(domain || '').toLowerCase().trim()
    .replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0].split(':')[0];
